<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Storage;
use Illuminate\Support\Facades\File;
use Illuminate\Support\Facades\Log;
use Symfony\Component\Process\Process;
use Symfony\Component\Process\Exception\ProcessFailedException;

class PdfReportController extends Controller
{
    /**
     * Generates a PDF report using wkhtmltopdf.
     *
     * @param Request $request
     * @return \Illuminate\Http\Response|\Illuminate\Http\JsonResponse
     */
    public function generate(Request $request)
    {
        // 1. Validate incoming request data
        $request->validate([
            'page_size' => 'nullable|string|max:50', // e.g., A4, Letter, 100mmx200mm
            'filename' => 'nullable|string|max:255|regex:/^[a-zA-Z0-9_-]+$/', // Alphanumeric, hyphens, underscores
            'view_name' => 'required|string|exists:reports_views,name', // Assuming 'reports_views' is a table mapping names to actual blade paths
            'report_data' => 'nullable|array', // Data to pass to the Blade view
            'orientation' => 'nullable|in:Portrait,Landscape', // wkhtmltopdf orientation
            'margin_top' => 'nullable|string', // e.g., 10mm
            'margin_right' => 'nullable|string',
            'margin_bottom' => 'nullable|string',
            'margin_left' => 'nullable|string',
        ]);

        // 2. Get parameters with defaults
        $pageSize = $request->input('page_size', 'A4');
        $filename = $request->input('filename', 'report_' . now()->format('Ymd_His')) . '.pdf';
        $viewName = $request->input('view_name');
        $reportData = $request->input('report_data', []);
        $orientation = $request->input('orientation', 'Portrait');

        // 3. Determine the actual Blade view path
        // This is a placeholder. In a real application, you might have a mapping
        // or a convention for where your report views are stored.
        // Example: 'reports.my_report' -> resources/views/reports/my_report.blade.php
        $bladeViewPath = 'reports.' . $viewName; // Adjust this based on your actual view structure

        if (!view()->exists($bladeViewPath)) {
            Log::error("PDF Generation Error: Blade view '{$bladeViewPath}' does not exist.");
            return response()->json(['error' => "Report template '{$viewName}' not found."], 404);
        }

        // 4. Render the Blade view to HTML
        try {
            $htmlContent = view($bladeViewPath, $reportData)->render();
        } catch (\Throwable $e) {
            Log::error("PDF Generation Error: Failed to render Blade view '{$bladeViewPath}'. " . $e->getMessage());
            return response()->json(['error' => 'Failed to render report content.', 'details' => $e->getMessage()], 500);
        }

        // 5. Create temporary files for HTML input and PDF output
        $tempDir = storage_path('app/temp_pdfs');
        if (!File::isDirectory($tempDir)) {
            File::makeDirectory($tempDir, 0755, true);
        }

        $tempHtmlFile = tempnam($tempDir, 'wkhtml_html_') . '.html';
        $tempPdfFile = tempnam($tempDir, 'wkhtml_pdf_') . '.pdf';

        File::put($tempHtmlFile, $htmlContent);

        // 6. Construct the wkhtmltopdf command
        // Ensure wkhtmltopdf is in your system's PATH or provide its full path.
        // Example: '/usr/local/bin/wkhtmltopdf' or 'C:\Program Files\wkhtmltopdf\bin\wkhtmltopdf.exe'
        $wkhtmltopdfPath = config('app.wkhtmltopdf_path', 'wkhtmltopdf'); // Make this configurable

        $command = [
            $wkhtmltopdfPath,
            '--enable-local-file-access', // Allows wkhtmltopdf to access local assets (CSS, images)
            '--page-size', $pageSize,
            '--orientation', $orientation,
        ];

        // Add margins if provided
        if ($request->has('margin_top')) {
            $command[] = '--margin-top';
            $command[] = $request->input('margin_top');
        }
        if ($request->has('margin_right')) {
            $command[] = '--margin-right';
            $command[] = $request->input('margin_right');
        }
        if ($request->has('margin_bottom')) {
            $command[] = '--margin-bottom';
            $command[] = $request->input('margin_bottom');
        }
        if ($request->has('margin_left')) {
            $command[] = '--margin-left';
            $command[] = $request->input('margin_left');
        }

        $command[] = $tempHtmlFile;
        $command[] = $tempPdfFile;

        // 7. Execute the wkhtmltopdf command using Symfony Process for better error handling
        try {
            $process = new Process($command);
            $process->setTimeout(300); // Set a timeout for the process (e.g., 5 minutes)
            $process->run();

            // Check if the command was successful
            if (!$process->isSuccessful()) {
                throw new ProcessFailedException($process);
            }

            // 8. Check if the PDF file was actually created
            if (!File::exists($tempPdfFile) || File::size($tempPdfFile) === 0) {
                Log::error("PDF Generation Error: wkhtmltopdf command executed, but no PDF file was created or it's empty. Output: " . $process->getOutput() . " Error: " . $process->getErrorOutput());
                return response()->json(['error' => 'Failed to generate PDF. Output file missing or empty.'], 500);
            }

            // 9. Return the generated PDF file as a download
            return response()->download($tempPdfFile, $filename)->deleteFileAfterSend(true);

        } catch (ProcessFailedException $exception) {
            Log::error("PDF Generation Error: wkhtmltopdf command failed. " . $exception->getMessage() . " Output: " . $exception->getProcess()->getOutput() . " Error: " . $exception->getProcess()->getErrorOutput());
            return response()->json(['error' => 'Failed to generate PDF report.', 'details' => $exception->getMessage(), 'output' => $exception->getProcess()->getOutput(), 'error_output' => $exception->getProcess()->getErrorOutput()], 500);
        } catch (\Throwable $e) {
            Log::error("PDF Generation Error: An unexpected error occurred. " . $e->getMessage());
            return response()->json(['error' => 'An unexpected error occurred during PDF generation.', 'details' => $e->getMessage()], 500);
        } finally {
            // 10. Clean up temporary HTML file
            if (File::exists($tempHtmlFile)) {
                File::delete($tempHtmlFile);
            }
            // The temporary PDF file is deleted by deleteFileAfterSend(true)
        }
    }
}

